// Extract and normalise Stripe event data for DocGen
const event       = $input.first().json;
const eventType   = event.type;
const dataObj     = event.data?.object || {};

// Determine event category
const isPaid      = eventType === 'invoice.paid';
const isFailed    = eventType === 'invoice.payment_failed';
const isTrialEnd  = eventType === 'customer.subscription.trial_will_end';
const isCancelled = eventType === 'customer.subscription.deleted';

// Plan mapping
const PLAN_MAP = {
  'price_starter_29':  { name: 'Starter',  price: 29,  docs: 50  },
  'price_pro_79':      { name: 'Pro',       price: 79,  docs: 500 },
  'price_team_199':    { name: 'Team',      price: 199, docs: 9999 },
};

const priceId   = dataObj.lines?.data?.[0]?.price?.id || dataObj.plan?.id || 'price_pro_79';
const planInfo  = PLAN_MAP[priceId] || { name: 'Pro', price: 79, docs: 500 };

const amountRaw = dataObj.amount_paid || dataObj.amount_due || dataObj.plan?.amount || 0;
const amount    = (amountRaw / 100).toFixed(2);
const tax       = (parseFloat(amount) * 0.10).toFixed(2);
const total     = (parseFloat(amount) + parseFloat(tax)).toFixed(2);

const trialEnd  = dataObj.trial_end
  ? new Date(dataObj.trial_end * 1000).toLocaleDateString('en-US', { year:'numeric', month:'long', day:'numeric' })
  : null;

const now = new Date();
const invoiceDate = now.toLocaleDateString('en-US', { year:'numeric', month:'long', day:'numeric' });
const invoiceNum  = `INV-${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}-${Math.floor(Math.random()*9000+1000)}`;

return [{
  json: {
    // Event metadata
    eventType,
    isPaid,
    isFailed,
    isTrialEnd,
    isCancelled,
    status: isPaid ? 'success' : isFailed ? 'failed' : isTrialEnd ? 'trial_ending' : 'cancelled',

    // Customer
    customerId:     dataObj.customer,
    customerEmail:  dataObj.customer_email || dataObj.billing_details?.email || 'customer@email.com',
    customerName:   dataObj.customer_name  || dataObj.billing_details?.name  || 'DocGen User',

    // Subscription
    subscriptionId: dataObj.subscription || dataObj.id,
    planName:       planInfo.name,
    planDocs:       planInfo.docs,
    priceId,

    // Payment
    amount,
    tax,
    total,
    currency:       (dataObj.currency || 'usd').toUpperCase(),
    paymentMethod:  dataObj.payment_intent || 'card',

    // Invoice
    invoiceId:      dataObj.id || invoiceNum,
    invoiceNumber:  invoiceNum,
    invoiceDate,
    trialEnd,

    // DocGen-specific
    productName:    `DocGen ${planInfo.name} Plan`,
    appUrl:         'https://docgen-q5j9d8vgam8vxnksgjkg4d.streamlit.app',
    repoUrl:        'https://github.com/softcopyacq/docgen',
  }
}];

