// Log trial activation — in production, use n8n's Schedule node
// or Stripe's trial_will_end webhook (fires 3 days before trial ends)
const d = $input.first().json;

if (d.isTrialEnd) {
  // Stripe already fires trial_will_end 3 days before end
  // This node confirms the reminder was processed
  console.log(`Trial ending reminder processed for: ${d.customerEmail}`);
}

return [{
  json: {
    ...d,
    reminderScheduled: true,
    reminderNote: `Trial-end reminder processed for ${d.customerEmail} on ${d.invoiceDate}`,
  }
}];
